import { COUNTS, SITE } from "@/lib/constants";
import { readDocBody } from "@/lib/docs-content";
import { source } from "@/lib/source";

// Markdown-for-Agents target. middleware.ts rewrites requests carrying
// `Accept: text/markdown` (or `?mode=agent`, or a `.md` suffix) for `/` and
// `/docs/*` here, so the same URL serves HTML to browsers and raw Markdown to
// agents. The raw .mdx files are bundled on Vercel via outputFileTracingIncludes
// in next.config.mjs.
// https://developers.cloudflare.com/fundamentals/reference/markdown-for-agents/
export const dynamic = "force-dynamic";

// `Vary: Accept` is required: the same URL returns HTML or Markdown depending on
// the Accept header, so a CDN must key its cache on it or it will serve the
// wrong variant (acceptmarkdown.com requirement).
const MD_HEADERS = {
	"Content-Type": "text/markdown; charset=utf-8",
	"Cache-Control": "public, max-age=3600",
	Vary: "Accept, Accept-Encoding",
} as const;

function homepageMarkdown(): string {
	const pages = source.getPages();
	return [
		`# ${SITE.name}`,
		"",
		`> AI development toolkit for Claude Code — ${COUNTS.skills} skills, ${COUNTS.agents} agents, ${COUNTS.hooks} hooks.`,
		"",
		"## Documentation",
		"",
		...pages.map(
			(p) => `- [${p.data.title}](${p.url}): ${p.data.description ?? ""}`,
		),
		"",
		"## Machine-readable resources",
		"",
		`- Full docs in one file: [${SITE.domain}/llms-full.txt](/llms-full.txt)`,
		`- Navigation index: [${SITE.domain}/llms.txt](/llms.txt)`,
		`- OpenAPI spec: [${SITE.domain}/api/openapi](/api/openapi)`,
		`- Natural-language query: POST [${SITE.domain}/ask](/ask)`,
		`- MCP server (Streamable HTTP): [${SITE.domain}/api/mcp](/api/mcp)`,
		"",
	].join("\n");
}

export async function GET(
	_req: Request,
	{ params }: { params: Promise<{ slug?: string[] }> },
) {
	const { slug } = await params;

	// Homepage (empty slug) — synthesize a markdown index.
	if (!slug || slug.length === 0) {
		return new Response(homepageMarkdown(), { headers: MD_HEADERS });
	}

	const page = source.getPage(slug);
	if (!page) return new Response("# Not found\n", { status: 404, headers: MD_HEADERS });

	const body = await readDocBody(page.slugs);
	const md = `# ${page.data.title}\n\n${page.data.description ?? ""}\n\n${body ?? ""}\n`;
	return new Response(md, { headers: MD_HEADERS });
}
